Let me write the complete implementation."},{"type":"tool_use","name":"write_file","input":{"file_path":"server/index.ts","content":"import express, { Express, Request, Response, NextFunction } from 'express';
import cors from 'cors';
import helmet from 'helmet';
import mongoose from 'mongoose';
import rateLimit from 'express-rate-limit';
import type { ServerConfig, AppDependencies, ExpressApp, MiddlewareConfig } from '../types';

// Default configuration
const defaultConfig: ServerConfig = {
  port: parseInt(process.env.PORT || '3000', 10),
  dbUri: process.env.DB_URI || 'mongodb://localhost:27017/auth_db',
  jwtSecret: process.env.JWT_SECRET || 'your-secret-key-change-in-production',
  corsOrigin: process.env.CORS_ORIGIN || 'http://localhost:5173',
  nodeEnv: (process.env.NODE_ENV as ServerConfig['nodeEnv']) || 'development',
};

// Database connection interface
export interface DatabaseConnection {
  connect(uri: string): Promise<void>;
  disconnect(): Promise<void>;
  isConnected(): boolean;
}

// Create MongoDB database connection
class MongoDatabase implements DatabaseConnection {
  private connected: boolean = false;

  async connect(uri: string): Promise<void> {
    try {
      mongoose.connection.on('connected', () => {
        this.connected = true;
        console.log('✅ MongoDB connected successfully');
      });

      mongoose.connection.on('error', (err) => {
        console.error('❌ MongoDB connection error:', err);
        this.connected = false;
      });

      mongoose.connection.on('disconnected', () => {
        this.connected = false;
        console.log('⚠️ MongoDB disconnected');
      });

      await mongoose.connect(uri, {
        maxPoolSize: 10,
        serverSelectionTimeoutMS: 5000,
        socketTimeoutMS: 45000,
      });

      this.connected = true;
    } catch (error) {
      console.error('❌ Failed to connect to MongoDB:', error);
      throw error;
    }
  }

  async disconnect(): Promise<void> {
    if (this.connected) {
      await mongoose.disconnect();
      this.connected = false;
    }
  }

  isConnected(): boolean {
    return this.connected;
  }
}

// Middleware configuration
const configureMiddleware = (app: Express, config: MiddlewareConfig): void => {
  // CORS configuration
  app.use(cors({
    origin: config.cors.origin,
    credentials: config.cors.credentials,
    methods: ['GET', 'POST', 'PUT', 'DELETE', 'PATCH', 'OPTIONS'],
    allowedHeaders: ['Content-Type', 'Authorization'],
  }));

  // Helmet security headers
  if (config.helmet) {
    app.use(helmet());
  }

  // JSON body parser
  app.use(express.json({ limit: config.json.limit }));
  app.use(express.urlencoded({ extended: true }));

  // Rate limiting (optional)
  if (config.rateLimit) {
    const limiter = rateLimit({
      windowMs: config.rateLimit.windowMs,
      max: config.rateLimit.max,
      message: { error: 'Too many requests, please try again later.' },
      standardHeaders: true,
      legacyHeaders: false,
    });
    app.use('/api', limiter);
  }
};

// Default middleware configuration
const getDefaultMiddlewareConfig = (corsOrigin: string): MiddlewareConfig => ({
  cors: {
    origin: corsOrigin,
    credentials: true,
  },
  json: {
    limit: '10kb',
  },
  helmet: true,
  rateLimit: {
    windowMs: 15 * 60 * 1000, // 15 minutes
    max: 100,
  },
});

// Request logging middleware
const requestLogger = (req: Request, res: Response, next: NextFunction): void => {
  const timestamp = new Date().toISOString();
  console.log(`[${timestamp}] ${req.method} ${req.path}`);
  next();
};

// Error handling middleware
const errorHandler = (err: Error, req: Request, res: Response, next: NextFunction): void => {
  console.error('Error:', err.message);
  console.error('Stack:', err.stack);

  res.status(500).json({
    error: 'Internal Server Error',
    message: process.env.NODE_ENV === 'development' ? err.message : undefined,
  });
};

// Not found handler
const notFoundHandler = (req: Request, res: Response): void => {
  res.status(404).json({
    error: 'Not Found',
    message: `Route ${req.method} ${req.path} not found`,
  });
};

// Create and configure Express app
const createApp = (middlewareConfig?: MiddlewareConfig): Express => {
  const app = express();
  const config = middlewareConfig || getDefaultMiddlewareConfig(defaultConfig.corsOrigin);

  // Apply middleware
  configureMiddleware(app, config);

  // Request logging
  app.use(requestLogger);

  // Health check endpoint
  app.get('/health', (req: Request, res: Response) => {
    res.json({
      status: 'ok',
      timestamp: new Date().toISOString(),
      uptime: process.uptime(),
    });
  });

  // API info endpoint
  app.get('/api', (req: Request, res: Response) => {
    res.json({
      name: 'User Authentication API',
      version: '1.0.0',
      endpoints: {
        auth: {
          register: 'POST /api/auth/register',
          login: 'POST /api/auth/login',
          logout: 'POST /api/auth/logout',
          refresh: 'POST /api/auth/refresh',
        },
        user: {
          getProfile: 'GET /api/users/profile',
          updateProfile: 'PUT /api/users/profile',
        },
      },
    });
  });

  // Error handlers
  app.use(notFoundHandler);
  app.use(errorHandler);

  return app;
};

// Server class
class Server implements AppDependencies {
  public app: Express;
  public db: DatabaseConnection;
  public config: ServerConfig;

  constructor(config: ServerConfig) {
    this.config = config;
    this.app = createApp();
    this.db = new MongoDatabase();
  }

  async start(): Promise<void> {
    try {
      // Connect to database
      console.log('🔄 Connecting to database...');
      await this.db.connect(this.config.dbUri);

      // Start Express server
      this.app.listen(this.config.port, () => {
        console.log(`
╔════════════════════════════════════════════════════════════╗
║                    Server Started                          ║
╠════════════════════════════════════════════════════════════╣
║  🌐 Environment: ${this.config.nodeEnv.padEnd(42)}║
║  🚀 Port:        ${String(this.config.port).padEnd(42)}║
║  📦 Database:    MongoDB                                   ║
║  🔗 CORS:        ${this.config.corsOrigin.substring(0, 42).padEnd(42)}║
╚════════════════════════════════════════════════════════════╝
        `);
      });

      // Graceful shutdown handlers
      this.setupGracefulShutdown();
    } catch (error) {
      console.error('❌ Failed to start server:', error);
      process.exit(1);
    }
  }

  private setupGracefulShutdown(): void {
    const shutdown = async (signal: string): Promise<void> => {
      console.log(`\n${signal} received. Starting graceful shutdown...`);

      try {
        await this.db.disconnect();
        console.log('✅ Database disconnected');
        console.log('👋 Server shutdown complete');
        process.exit(0);
      } catch (error) {
        console.error('❌ Error during shutdown:', error);
        process.exit(1);
      }
    };

    process.on('SIGTERM', () => shutdown('SIGTERM'));
    process.on('SIGINT', () => shutdown('SIGINT'));

    process.on('uncaughtException', (error) => {
      console.error('❌ Uncaught Exception:', error);
      shutdown('UNCAUGHT_EXCEPTION');
    });

    process.on('unhandledRejection', (reason, promise) => {
      console.error('❌ Unhandled Rejection at:', promise, 'reason:', reason);
    });
  }
}

// Factory function to create server
export const createServer = (config?: Partial<ServerConfig>): Server => {
  const serverConfig: ServerConfig = {
    ...defaultConfig,
    ...config,
  };
  return new Server(serverConfig);
};

// Export default factory
export default createServer;

// Export classes and types for testing
export { Server, MongoDatabase, createApp, configureMiddleware };
