} from '../types';

// Mock product data for demonstration
const mockProducts: DbProduct[] = [
  { id: '1', name: 'Wireless Headphones', price: 99.99, category: 'Electronics', description: 'High-quality wireless headphones with noise cancellation', imageUrl: '/images/headphones.jpg', stock: 50, createdAt: new Date().toISOString() },
  { id: '2', name: 'Running Shoes', price: 129.99, category: 'Sports', description: 'Comfortable running shoes for all terrains', imageUrl: '/images/shoes.jpg', stock: 30, createdAt: new Date().toISOString() },
  { id: '3', name: 'Coffee Maker', price: 79.99, category: 'Home', description: 'Automatic coffee maker with timer', imageUrl: '/images/coffee.jpg', stock: 25, createdAt: new Date().toISOString() },
  { id: '4', name: 'Laptop Stand', price: 49.99, category: 'Electronics', description: 'Ergonomic laptop stand for better posture', imageUrl: '/images/stand.jpg', stock: 40, createdAt: new Date().toISOString() },
  { id: '5', name: 'Yoga Mat', price: 34.99, category: 'Sports', description: 'Non-slip yoga mat for home workouts', imageUrl: '/images/yoga.jpg', stock: 60, createdAt: new Date().toISOString() },
];

const mockCategories = ['All', 'Electronics', 'Sports', 'Home'];

// SearchBar Component
const SearchBar: React.FC<SearchBarProps> = ({
  value,
  onSubmit,
  onChange,
  placeholder = 'Search products...',
}) => {
  const handleSubmit = (e: React.FormEvent) => {
