      />
      <button type="submit" className="search-button">
        Search
      </button>
    </form>
  );
};

// CategoryFilter Component
const CategoryFilter: React.FC<CategoryFilterProps> = ({
  categories,
  selectedCategory,
  onSelect,
}) => {
  const categoryOptions: CategoryOption[] = categories.map((cat) => ({
    label: cat,
    value: cat === 'All' ? '' : cat,
  }));

  return (
    <div className="category-filter">
