// Main HomePage Component
const HomePage: React.FC<HomePageProps> = () => {
  const [state, setState] = useState<HomePageState>({
    products: [],
    categories: mockCategories,
    isLoading: true,
    error: null,
    currentPage: 1,
    totalPages: 1,
    searchQuery: '',
    selectedCategory: '',
    pageSize: 12,
  });

  const [status, setStatus] = useState<HomePageStatus>({ status: 'loading' });

  // Simulated data loading
  React.useEffect(() => {
    const loadProducts = async () => {
      setState((prev) => ({ ...prev, isLoading: true, error: null }));
      setStatus({ status: 'loading' });

      try {
        // Simulate API call
        await new Promise((resolve) => setTimeout(resolve, 1000));

        const filteredProducts = mockProducts.filter((product) => {
          const matchesSearch = state.searchQuery
            ? product.name.toLowerCase().includes(state.searchQuery.toLowerCase()) ||
              product.description.toLowerCase().includes(state.searchQuery.toLowerCase())
            : true;
          const matchesCategory = state.selectedCategory
            ? product.category === state.selectedCategory
            : true;
          return matchesSearch && matchesCategory;
        });

        const totalPages = Math.ceil(filteredProducts.length / state.pageSize);

        setState((prev) => ({
          ...prev,
          products: filteredProducts,
          isLoading: false,
          totalPages: totalPages || 1,
        }));
        setStatus({
          status: 'loaded',
          products: filteredProducts,
          categories: mockCategories,
          currentPage: state.currentPage,
          totalPages: totalPages || 1,
        });
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : 'Failed to load products';
        setState((prev) => ({ ...prev, isLoading: false, error: errorMessage }));
        setStatus({ status: 'error', error: errorMessage });
      }
    };

    loadProducts();
  }, [state.searchQuery, state.selectedCategory, state.currentPage, state.pageSize]);

  // Event Handlers
  const onSearch = useCallback((query: string) => {
    setState((prev) => ({ ...prev, searchQuery: query, currentPage: 1 }));
  }, []);

  const onCategoryChange = useCallback((category: string) => {
    setState((prev) => ({ ...prev, selectedCategory: category, currentPage: 1 }));
  }, []);

  const onPageChange = useCallback((page: number) => {
    setState((prev) => ({ ...prev, currentPage: page }));
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, []);

  const onProductClick = useCallback((productId: string) => {
    console.log('Product clicked:', productId);
    // Navigate to product detail page
    // router.push(`/product/${productId}`);
  }, []);

  const onRetry = useCallback(() => {
    setState((prev) => ({ ...prev, isLoading: true, error: null }));
    setStatus({ status: 'loading' });
  }, []);

  const onClearSearch = useCallback(() => {
    setState((prev) => ({ ...prev, searchQuery: '', currentPage: 1 }));
  }, []);

  const handlers: HomePageHandlers = {
    onSearch,
    onCategoryChange,
    onPageChange,
    onProductClick,
    onRetry,
    onClearSearch,
  };

  // Computed values
  const paginatedProducts = useMemo(() => {
    const start = (state.currentPage - 1) * state.pageSize;
    const end = start + state.pageSize;
    return state.products.slice(start, end);
  }, [state.products, state.currentPage, state.pageSize]);

  const categoryOptions: CategoryOption[] = state.categories.map((cat) => ({
    label: cat,
    value: cat === 'All' ? '' : cat,
    count: cat === 'All' ? mockProducts.length : mockProducts.filter((p) => p.category === cat).length,
  }));

  // Render based on status
  const renderContent = () => {
    switch (status.status) {
      case 'loading':
        return <HomePageLoading />;
      case 'error':
        return <HomePageError error={status.error} onRetry={handlers.onRetry} />;
      case 'loaded':
        return (
          <div className="home-content">
            <header className="home-header">
              <h1>Welcome to Our Store</h1>
              <p>Discover amazing products across all categories</p>
            </header>

            <section className="search-section">
              <SearchBar
                value={state.searchQuery}
                onSubmit={handlers.onSearch}
                onChange={(value) => setState((prev) => ({ ...prev, searchQuery: value }))}
                placeholder="Search for products..."
              />
            </section>

            <section className="filter-section">
              <CategoryFilter
                categories={categoryOptions}
                selectedCategory={state.selectedCategory}
                onSelect={handlers.onCategoryChange}
              />
            </section>

            {state.products.length === 0 ? (
              <div className="no-results">
                <p>No products found. Try adjusting your search or filters.</p>
                <button onClick={handlers.onClearSearch} className="clear-button">
                  Clear Search
                </button>
              </div>
            ) : (
              <>
                <section className="products-section">
                  <div className="products-grid">
                    {paginatedProducts.map((product, index) => (
                      <ProductCard
                        key={product.id}
                        product={product}
                        onClick={handlers.onProductClick}
                        isFeatured={index < 3}
                      />
                    ))}
                  </div>
                </section>

                <section className="pagination-section">
                  <Pagination
                    currentPage={state.currentPage}
                    totalPages={state.totalPages}
                    onPageChange={handlers.onPageChange}
                    maxVisiblePages={5}
                  />
                </section>
              </>
            )}
          </div>
        );
    }
  };

  return (
    <div className="home-page">
      {renderContent()}
    </div>
  );
};

export default HomePage;

// Export types for external use
export type {
  HomePageState,
  HomePageHandlers,
  HomePageProps,
  CategoryOption,
  ProductCardProps,
  PaginationProps,
  SearchBarProps,
  CategoryFilterProps,
  HomePageStatus,
};
"}},{"type":"tool_use","name":"write_file","input":{"file_path":"src/pages/Login.tsx","content":"import React, { useState, useCallback, useMemo, useEffect } from 'react';
import type {
  AuthMode,
  LoginFormData,
  RegisterFormData,
  LoginPageFormData,
  LoginPageErrors,
  LoginPageState,
  LoginPageHandlers,
  LoginPageProps,
  FormFieldValidation,
  ValidationRule,
  LoginFormProps,
  RegisterFormProps,
  AuthModeToggleProps,
} from '../types';

// Validation Helper Functions
const validators = {
  required: (value: string): boolean => value.trim().length > 0,
  minLength: (value: string, min: number): boolean => value.length >= min,
  maxLength: (value: string, max: number): boolean => value.length <= max,
  email: (value: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(value);
  },
  match: (value: string, matchValue: string): boolean => value === matchValue,
};

const validateField = (
  field: keyof LoginPageFormData,
  value: string,
  allFormData: LoginPageFormData,
  rules: ValidationRule[]
): string | undefined => {
  for (const rule of rules) {
    let isValid = false;

    switch (rule.type) {
      case 'required':
        isValid = validators.required(value);
        break;
      case 'minLength':
        isValid = validators.minLength(value, rule.value);
        break;
      case 'maxLength':
        isValid = validators.maxLength(value, rule.value);
        break;
      case 'email':
        isValid = validators.email(value);
        break;
      case 'match':
        isValid = validators.match(value, rule.value as string);
        break;
      case 'custom':
        isValid = rule.validator ? rule.validator(value) : true;
        break;
      default:
        isValid = true;
    }

    if (!isValid) {
      return rule.message;
    }
  }

  return undefined;
};

// Auth Mode Toggle Component
const AuthModeToggle: React.FC<AuthModeToggleProps> = ({ mode, onToggle }) => {
  return (
    <div className="auth-mode-toggle">
      <button
        type="button"
        onClick={onToggle}
        className="mode-toggle-button"
        aria-pressed={mode === 'register'}
      >
        {mode === 'login' ? (
          <>
            Don't have an account? <span className="toggle-link">Sign up</span>
          </>
        ) : (
          <>
            Already have an account? <span className="toggle-link">Sign in</span>
          </>
        )}
      </button>
    </div>
  );
};

// Login Form Component
const LoginForm: React.FC<LoginFormProps> = ({
  formData,
  errors,
  isLoading,
  onSubmit,
  onFieldChange,
}) => {
  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit();
  };

  return (
    <form onSubmit={handleSubmit} className="login-form" noValidate>
      <div className="form-field">
        <label htmlFor="email" className="form-label">
          Email Address
        </label>
        <input
          type="email"
          id="email"
          name="email"
          value={formData.email}
          onChange={(e) => onFieldChange('email', e.target.value)}
          className={`form-input ${errors.email ? 'error' : ''}`}
          placeholder="Enter your email"
          disabled={isLoading}
          autoComplete="email"
        />
        {errors.email && (
          <span className="field-error" role="alert">
            {errors.email}
          </span>
        )}
      </div>

      <div className="form-field">
        <label htmlFor="password" className="form-label">
          Password
        </label>
        <input
          type="password"
