  }, []);

  const onClearSearch = useCallback(() => {
    setState((prev) => ({ ...prev, searchQuery: '', currentPage: 1 }));
  }, []);

  const handlers: HomePageHandlers = {
    onSearch,
    onCategoryChange,
    onPageChange,
    onProductClick,
    onRetry,
    onClearSearch,
  };

  // Computed values
  const paginatedProducts = useMemo(() => {
    const start = (state.currentPage - 1) * state.pageSize;
    const end = start + state.pageSize;
    return state.products.slice(start, end);
  }, [state.products, state.currentPage, state.pageSize]);

  const categoryOptions: CategoryOption[] = state.categories.map((cat) => ({
    label: cat,
    value: cat === 'All' ? '' : cat,
    count: cat === 'All' ? mockProducts.length : mockProducts.filter((p) => p.category === cat).length,
  }));

  // Render based on status
  const renderContent = () => {
    switch (status.status) {
      case 'loading':
        return <HomePageLoading />;
      case 'error':
        return <HomePageError error={status.error} onRetry={handlers.onRetry} />;
      case 'loaded':
        return (
          <div className="home-content">
            <header className="home-header">
              <h1>Welcome to Our Store</h1>
              <p>Discover amazing products across all categories</p>
            </header>

            <section className="search-section">
              <SearchBar
                value={state.searchQuery}
                onSubmit={handlers.onSearch}
                onChange={(value) => setState((prev) => ({ ...prev, searchQuery: value }))}
