const LoginPage: React.FC<LoginPageProps> = ({
  onLoginSuccess,
  onRegisterSuccess,
  redirectTo = '/',
}) => {
  const [state, setState] = useState<LoginPageState>({
    mode: 'login',
    formData: {
      name: '',
      email: '',
      password: '',
      confirmPassword: '',
    },
    errors: {},
    isLoading: false,
    serverError: null,
    isFormValid: false,
  });

  // Validation rules
  const validationRules: Record<keyof LoginPageFormData, ValidationRule[]> = {
    name: [
      { type: 'required', message: 'Name is required' },
      { type: 'minLength', value: 2, message: 'Name must be at least 2 characters' },
      { type: 'maxLength', value: 50, message: 'Name must not exceed 50 characters' },
    ],
    email: [
      { type: 'required', message: 'Email is required' },
      { type: 'email', message: 'Please enter a valid email address' },
    ],
    password: [
      { type: 'required', message: 'Password is required' },
      { type: 'minLength', value: 8, message: 'Password must be at least 8 characters' },
      {
        type: 'custom',
        message: 'Password must contain at least one number',
        validator: (val) => /\d/.test(val),
      },
    ],
    confirmPassword: [
      { type: 'required', message: 'Please confirm your password' },
      {
        type: 'match',
        value: state.formData.password,
        message: 'Passwords do not match',
      },
    ],
  };

  // Form field validation
  const validateForm = useCallback((): boolean => {
    const newErrors: LoginPageErrors = {};
    let isValid = true;

    const fieldsToValidate: (keyof LoginPageFormData)[] =
      state.mode === 'login'
        ? ['email', 'password']
        : ['name', 'email', 'password', 'confirmPassword'];

    for (const field of fieldsToValidate) {
      const error = validateField(field, state.formData[field], state.formData, validationRules[field]);
      if (error) {
        newErrors[field] = error;
        isValid = false;
      }
    }

    setState((prev) => ({ ...prev, errors: newErrors, isFormValid: isValid }));
    return isValid;
  }, [state.formData, state.mode, validationRules]);

  // Check form validity when fields change
  useEffect(() => {
    validateForm();
  }, [state.formData, state.mode]);

  // Event Handlers
  const onSubmit = useCallback(async () => {
    if (!validateForm()) {
      return;
    }

    setState((prev) => ({ ...prev, isLoading: true, serverError: null }));

    try {
      // Simulate API call
      await new Promise((resolve) => setTimeout(resolve, 1500));

      // Mock successful response
      const mockToken = 'mock-jwt-token-' + Date.now();

      if (state.mode === 'login') {
        if (onLoginSuccess) {
          onLoginSuccess(mockToken);
        }
      } else {
        if (onRegisterSuccess) {
          onRegisterSuccess(mockToken);
        }
      }

      // Redirect after successful auth
      console.log('Redirect to:', redirectTo);
      // router.push(redirectTo);
    } catch (error) {
      const errorMessage =
        error instanceof Error ? error.message : 'An unexpected error occurred. Please try again.';
      setState((prev) => ({
        ...prev,
        isLoading: false,
        serverError: errorMessage,
      }));
    }
  }, [state.mode, validateForm, onLoginSuccess, onRegisterSuccess, redirectTo]);

  const onModeToggle = useCallback(() => {
    setState((prev) => ({
      ...prev,
      mode: prev.mode === 'login' ? 'register' : 'login',
      errors: {},
      serverError: null,
      isFormValid: false,
    }));
  }, []);

  const onFieldChange = useCallback(
    (field: keyof LoginPageFormData, value: string) => {
      setState((prev) => ({
        ...prev,
        formData: { ...prev.formData, [field]: value },
        errors: { ...prev.errors, [field]: undefined },
      }));
    },
    []
  );

  const onClearError = useCallback((field: keyof LoginPageErrors) => {
    setState((prev) => ({
      ...prev,
      errors: { ...prev.errors, [field]: undefined },
    }));
  }, []);

  const onClearServerError = useCallback(() => {
    setState((prev) => ({ ...prev, serverError: null }));
  }, []);

  const handlers: LoginPageHandlers = {
    onSubmit,
    onModeToggle,
    onFieldChange,
    onClearError,
    onClearServerError,
  };

  // Derived form data
  const loginFormData: LoginFormData = {
    email: state.formData.email,
    password: state.formData.password,
  };

  const registerFormData: RegisterFormData = {
    name: state.formData.name,
    email: state.formData.email,
    password: state.formData.password,
    confirmPassword: state.formData.confirmPassword,
  };

  const loginErrors: Pick<LoginPageErrors, 'email' | 'password'> = {
    email: state.errors.email,
    password: state.errors.password,
  };

  const registerErrors: Pick<LoginPageErrors, 'name' | 'email' | 'password' | 'confirmPassword'> = {
    name: state.errors.name,
    email: state.errors.email,
    password: state.errors.password,
    confirmPassword: state.errors.confirmPassword,
  };

  return (
    <div className="login-page">
      <div className="login-container">
        <header className="login-header">
          <h1 className="login-title">
            {state.mode === 'login' ? 'Welcome Back' : 'Create Account'}
          </h1>
          <p className="login-subtitle">
            {state.mode === 'login'
              ? 'Sign in to continue to your account'
              : 'Join us and start your journey'}
          </p>
        </header>

        {state.serverError && (
          <ServerError error={state.serverError} onDismiss={handlers.onClearServerError} />
        )}

        {state.mode === 'login' ? (
          <LoginForm
            formData={loginFormData}
            errors={loginErrors}
            isLoading={state.isLoading}
            onSubmit={handlers.onSubmit}
            onFieldChange={handlers.onFieldChange}
          />
        ) : (
          <RegisterForm
            formData={registerFormData}
            errors={registerErrors}
            isLoading={state.isLoading}
            onSubmit={handlers.onSubmit}
            onFieldChange={handlers.onFieldChange}
          />
        )}

        <AuthModeToggle mode={state.mode} onToggle={handlers.onModeToggle} />

        <footer className="login-footer">
          <p className="footer-text">
            By continuing, you agree to our{' '}
            <a href="/terms" className="footer-link">
              Terms of Service
            </a>{' '}
            and{' '}
            <a href="/privacy" className="footer-link">
              Privacy Policy
            </a>
          </p>
        </footer>
      </div>
    </div>
  );
};

