// [FILE: src/services/api.ts]
// 前端 API 服务类型

export interface ApiClientConfig {
  baseURL: string;
  timeout?: number;
  headers?: Record<string, string>;
}

export interface RequestInterceptor {
  onRequest?: (config: RequestConfig) => RequestConfig | Promise<RequestConfig>;
  onRequestError?: (error: any) => any;
}

export interface ResponseInterceptor {
  onResponse?: (response: any) => any;
  onResponseError?: (error: any) => any;
}

export interface RequestConfig {
  url: string;
  method: 'GET' | 'POST' | 'PUT' | 'DELETE' | 'PATCH';
  headers?: Record<string, string>;
  params?: Record<string, any>;
  data?: any;
  timeout?: number;
}

export interface ApiClientInstance {
  get<T>(url: string, params?: Record<string, any>): Promise<T>;
  post<T>(url: string, data?: any): Promise<T>;
  put<T>(url: string, data?: any): Promise<T>;
  delete<T>(url: string): Promise<T>;
  setAuthToken(token: string | null): void;
  getAuthToken(): string | null;
  clearAuthToken(): void;
}

export interface ApiServiceEndpoints {
  auth: {
    register(data: RegisterRequest): Promise<RegisterResponse>;
    login(data: LoginRequest): Promise<LoginResponse>;
    logout(): Promise<LogoutResponse>;
    getMe(): Promise<MeResponse>;
  };
  products: {
    list(params?: ProductQueryParams): Promise<ProductsListResponse>;
    getById(id: string): Promise<ProductDetailResponse>;
    create(data: CreateProductRequest): Promise<CreateProductResponse>;
    update(id: string, data: UpdateProductRequest): Promise<UpdateProductResponse>;
    delete(id: string): Promise<DeleteProductResponse>;
  };
  users: {
    list(params?: UserQueryParams): Promise<UsersListResponse>;
    getById(id: string): Promise<UserDetailResponse>;
    update(id: string, data: UpdateUserRequest): Promise<UpdateUserResponse>;
    delete(id: string): Promise<DeleteUserResponse>;
  };
}

